## TDD RED: unit tests for strip_unknown_params()

### File to create/extend: tests/unit/test_request_compat.py

Add a new test class at the end of the existing file.

### What strip_unknown_params does

```python
def strip_unknown_params(
    params: dict[str, Any],
    known_params: set[str],
) -> tuple[dict[str, Any], list[str]]:
```

Takes a params dict and a set of known parameter names (from tool.parameters["properties"].keys()).
Returns (cleaned_dict_with_only_known_keys, list_of_stripped_key_names).
Pure function. No logging (caller logs).

### Test cases

```python
class TestStripUnknownParams:

    def test_all_known_fields_pass_through(self):
        cleaned, stripped = strip_unknown_params(
            {"brief": "ads", "brand": {"domain": "acme.com"}},
            {"brief", "brand"},
        )
        assert cleaned == {"brief": "ads", "brand": {"domain": "acme.com"}}
        assert stripped == []

    def test_unknown_fields_removed(self):
        cleaned, stripped = strip_unknown_params(
            {"brief": "ads", "foo": "bar", "baz": 123},
            {"brief"},
        )
        assert cleaned == {"brief": "ads"}
        assert set(stripped) == {"foo", "baz"}

    def test_all_unknown_returns_empty(self):
        cleaned, stripped = strip_unknown_params(
            {"foo": 1, "bar": 2},
            {"brief", "brand"},
        )
        assert cleaned == {}
        assert set(stripped) == {"foo", "bar"}

    def test_empty_params_returns_empty(self):
        cleaned, stripped = strip_unknown_params({}, {"brief"})
        assert cleaned == {}
        assert stripped == []

    def test_preserves_none_values_for_known_fields(self):
        cleaned, stripped = strip_unknown_params(
            {"brief": None, "unknown": "x"},
            {"brief"},
        )
        assert cleaned == {"brief": None}
        assert stripped == ["unknown"]
```

